use sqlx::PgPool;

use crate::domain::{Password, User, UserId, ValidatedEmail};

pub struct UserRepository;

impl UserRepository {
    #[tracing::instrument(name = "Saving new user in the database", skip(pool, user))]
    pub async fn insert(pool: &PgPool, user: &User) -> Result<(), sqlx::Error> {
        sqlx::query!(
            r#"
            INSERT INTO users (id, email, password_hash)
            VALUES ($1, $2, $3)
            "#,
            user.id.as_uuid(),
            user.email.as_str(),
            user.password.hash(),
        )
        .execute(pool)
        .await?;
        Ok(())
    }

    #[tracing::instrument(name = "Looking up user by email", skip(pool))]
    pub async fn find_by_email(
        pool: &PgPool,
        email: &str,
    ) -> Result<Option<User>, sqlx::Error> {
        let row = sqlx::query!(
            r#"
            SELECT id, email, password_hash
            FROM users
            WHERE email = $1
            "#,
            email,
        )
        .fetch_optional(pool)
        .await?;

        Ok(row.map(|r| User {
            id: UserId::from_uuid(r.id),
            email: ValidatedEmail::parse(r.email)
                .expect("Database should contain valid emails"),
            password: Password::from_hash(r.password_hash),
        }))
    }
}

