use uuid::Uuid;

use super::{Password, ValidatedEmail};

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct UserId(Uuid);

impl UserId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

impl Default for UserId {
    fn default() -> Self {
        Self::new()
    }
}

impl std::fmt::Display for UserId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        self.0.fmt(f)
    }
}

#[derive(Debug, Clone)]
pub struct User {
    pub id: UserId,
    pub email: ValidatedEmail,
    pub password: Password,
}

impl User {
    pub fn new(email: ValidatedEmail, password: Password) -> Self {
        Self {
            id: UserId::new(),
            email,
            password,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn user_id_generates_unique_values() {
        let id1 = UserId::new();
        let id2 = UserId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn user_is_created_with_email_and_password() {
        let email = ValidatedEmail::parse("test@example.com".to_string()).unwrap();
        let password = Password::parse("securepassword").unwrap();
        let user = User::new(email.clone(), password);

        assert_eq!(user.email, email);
    }
}

CREATE TABLE users (
    id UUID PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
